def detect_smurfing(transactions):
    """Detects smurfing behavior in a list of transactions."""
    threshold = 10000
    transfers = {}
    smurfing = False

    for transaction in transactions:
        previous_amount = transfers.get(transaction['id'], 0)
        current_amount = previous_amount + transaction['amount']

        if current_amount > threshold:
            # If a single transaction exceeds the threshold, it's not smurfing
            if previous_amount == 0:
                smurfing = False
            # If a transaction exceeds 5,000 and it's part of a series (more than one transaction from the same sender), it's smurfing
            if previous_amount > 5000 and transactions[transactions.index(transaction) + 1]['id'] == transaction['id']:
                smurfing = True
